  <change>
    <file>App.tsx</file>
    <description>Fix ErrorBoundary types by using React.Component, and property initializer for state, and ensuring React.Component correctly provides props</description>
    <content><![CDATA[import React, { useState, useEffect, useCallback, ReactNode } from 'react';
import { generateAllMarketData, runSimulation } from './services/dataService';
import SimulationChart from './components/SimulationChart';
import ControlPanel from './components/ControlPanel';
import { DataPoint, SimulationConfig } from './types';

// Error Boundary to catch render issues
interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
}

class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  state: ErrorBoundaryState = { hasError: false };

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo): void {
    console.error('Caught error:', error, errorInfo);
  }

  render(): React.ReactNode {
    if (this.state.hasError) {
      return (
        <div>
          <h2>Something went wrong.</h2>
          {/* You can render an error message or fallback UI here */}
        </div>
      );
    }

    return this.props.children;
  }
}

function App() {
  const [marketData, setMarketData] = useState<DataPoint[]>([]);
  const [simulationConfig, setSimulationConfig] = useState<SimulationConfig>({
    numSimulations: 5,
    initialCapital: 100000,
    volatility: 0.15,
    drift: 0.05,
    timePeriods: 252,
  });
  const [loading, setLoading] = useState(false);

  const fetchData = useCallback(async () => {
    setLoading(true);
    const data = await generateAllMarketData(simulationConfig);
    setMarketData(data);
    setLoading(false);
  }, [simulationConfig]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const runSimulationAsync = useCallback(async (newConfig: SimulationConfig) => {
    setLoading(true);
    setSimulationConfig(newConfig);
    await fetchData();
    setLoading(false);
  }, [fetchData]);

  return (
    <div className="App">
      <h1>Market Simulation</h1>
      <ControlPanel
        onSubmit={runSimulationAsync}
        simulationConfig={simulationConfig}
        isLoading={loading}
      />
      {marketData.length > 0 && (
        <ErrorBoundary>
          <SimulationChart data={marketData} />
        </ErrorBoundary>
      )}
      {loading && <p>Loading...</p>}
    </div>
  );
}

export default App;
]]></content>
  </change>
</changes>
