// WEEKLY Interpolation helper with Noise
const interpolateWeekly = (
  startAnchor: number[], 
  endAnchor: number[], 
  name: string, 
  type: 'Reference' | 'Target'
): DataPoint[] => {
  const points: DataPoint[] = [];
  const [sy, sm, sd, sVal] = startAnchor;
  const [ey, em, ed, eVal] = endAnchor;

  const startDate = new Date(sy, sm - 1, sd);
  const endDate = new Date(ey, em - 1, ed);

  // Difference in milliseconds
  const diffTime = Math.abs(endDate.getTime() - startDate.getTime());
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 
  const totalWeeks = Math.floor(diffDays / 7);

  // Weekly Volatility (Approx 2-3%)
  let volatility = 0.02; 
  if (name.includes('KOSDAQ') || name.includes('NASDAQ')) volatility = 0.035;

  for (let i = 0; i <= totalWeeks; i++) {
    const ratio = i / totalWeeks;

    // Linear path
    const linearTarget = sVal + (eVal - sVal) * ratio;

    // Brownion bridge style noise
    // Max noise in the middle of the segment
    const bridgeFactor = 1 - Math.abs(ratio - 0.5) * 2; 
    const randomShift = randomNormal(0, linearTarget * volatility) * bridgeFactor;

    // Combine
    const val = linearTarget + randomShift;

    // Calculate Date
    const d = new Date(startDate);
    d.setDate(d.getDate() + (i * 7));

    // Stop if we go past end date
    if (d.getTime() > endDate.getTime() && i < totalWeeks) continue;
    if (i === totalWeeks) {
       // Force match end anchor
       points.push({
        date: formatDate(endDate),
        timestamp: endDate.getTime(),
        value: eVal,
        type: type,
        marketName: name,
        scenario: 'history'
      });
      break;
    }

    points.push({
      date: formatDate(d),
      timestamp: d.getTime(),
      value: val,
      type: type,
      marketName: name,
      scenario: 'history'
    });
  }

  return points;
};

const generateRealData = (anchors: number[][], name: string, type: 'Reference' | 'Target'): DataPoint[] => {
  let allPoints: DataPoint[] = [];

  const sortedAnchors = [...anchors].sort((a, b) => {
    const dateA = new Date(a[0], a[1]-1, a[2]).getTime();
    const dateB = new Date(b[0], b[1]-1, b[2]).getTime();
    return dateA - dateB;
  });

  for (let i = 0; i < sortedAnchors.length - 1; i++) {
    const segment = interpolateWeekly(sortedAnchors[i], sortedAnchors[i+1], name, type);
    // Remove the first point of the new segment to avoid duplication with the last point of previous segment
    if (i > 0) segment.shift();
    allPoints = allPoints.concat(segment);
  }

  return allPoints;
};

