  const nasdaqData = generateRealData(ANCHORS_NASDAQ, 'NASDAQ', 'Reference');
  const dowData = generateRealData(ANCHORS_DOWJONES, 'Dow Jones', 'Reference');
  const kospiData = generateRealData(ANCHORS_KOSPI, 'KOSPI', 'Target');
  const kosdaqData = generateRealData(ANCHORS_KOSDAQ, 'KOSDAQ', 'Target');

  return { japanData, sp500Data, nasdaqData, dowData, kospiData, kosdaqData };
};

// ------------------------------------------------------------------
// AI MODEL SIMULATION MATHEMATICS
// ------------------------------------------------------------------

// 1. LSTM/GRU Style: Memory-based, Momentum-heavy, Smoother
const calculateLSTMNextStep = (prevVal: number, drift: number, volatility: number, momentum: number): { val: number, momentum: number } => {
    const noise = randomNormal(0, volatility);
    // LSTM logic: Current state heavily depends on previous "cell state" (momentum)
    // Tanh activation simulation: limit extreme jumps
    const newMomentum = (momentum * 0.7) + (drift * 0.3) + (noise * 0.1); 
    const step = newMomentum * prevVal;
    return { val: prevVal + step, momentum: newMomentum };
};

// 2. XGBoost/LGBM Style: Decision Tree simulation, Non-linear, Regime Switching
const calculateBoostingNextStep = (prevVal: number, drift: number, volatility: number): number => {
    // Boosting logic: Step functions. Small steps mostly, but occasionally a "tree split" causes a jump.
    const noise = randomNormal(0, volatility);
    let jump = 0;
    // Regime switch probability
    if (Math.random() > 0.85) {
        jump = (Math.random() - 0.5) * volatility * 3.0; // Significant shock
    }
    // Drift is applied as a baseline score
    return prevVal * (1 + drift + noise + jump);
};

// 3. Fama-French (Standard): Linear Factor
const calculateStandardNextStep = (prevVal: number, drift: number, volatility: number): number => {
    const noise = randomNormal(0, volatility);
    return prevVal * (1 + drift + noise);
};


export const runSimulation = (
  historyData: DataPoint[], 
  config: SimulationConfig
): { alt1: DataPoint[], alt2: DataPoint[], alt3: DataPoint[], metrics: SimulationMetrics } => {
  const alt1: DataPoint[] = []; // Worst
  const alt2: DataPoint[] = []; // Moderate
  const alt3: DataPoint[] = []; // Best

  if (!historyData || historyData.length === 0) {
      return { alt1, alt2, alt3, metrics: { worstCAGR: 0, moderateCAGR: 0, bestCAGR: 0 } };
  }

  const lastPoint = historyData[historyData.length - 1];
  const startValue = lastPoint.value;
  const startDate = new Date(lastPoint.timestamp);

  // Convert Annual Rate to Weekly (52 weeks)
  const toWeeklyRate = (annualRate: number) => Math.pow(1 + annualRate, 1/52) - 1;

  // Base Market Params
  let annualBaseGrowth = 0.08; 
  let volatilityRef = 0.04; 

  switch (config.referenceMarket) {
    case 'Japan':
      annualBaseGrowth = 0.09; 
      volatilityRef = 0.04;
      break;
    case 'SP500':
      annualBaseGrowth = 0.10;  
      volatilityRef = 0.035;
      break;
    case 'NASDAQ':
      annualBaseGrowth = 0.14; 
      volatilityRef = 0.055;
      break;
    case 'DowJones':
      annualBaseGrowth = 0.085;
      volatilityRef = 0.03;
      break;
  }

  // Fama-French Factor Premiums (Hypothetical Annualized)
  const RISK_FREE_RATE = 0.035;
  const SMB_PREMIUM = 0.030; // Small Minus Big
  const RMW_PREMIUM = 0.035; // Robust Minus Weak (Profit)
  const CMA_PREMIUM = 0.030; // Conservative Minus Aggressive (Invest)
  const HML_PREMIUM = 0.040; // High Minus Low (Value)

  // Market Premium (Rm - Rf)
  const marketPremium = annualBaseGrowth - RISK_FREE_RATE;

  // Volatility adjustment
  const simVol = (volatilityRef / 2.0) * (config.volatility / 5.0);
  const totalWeeks = Math.floor(config.durationMonths * 4.345); 

  let val1 = startValue; // Worst
  let val2 = startValue; // Moderate
  let val3 = startValue; // Best

  // LSTM State Memory
  let m1 = 0; let m2 = 0; let m3 = 0;

  // --- Factor Loading Calculations & Theoretical Metrics ---
  // E(R) = Rf + b(Rm-Rf) + s(SMB) + h(HML) + r(RMW) + c(CMA)

  // Worst: Low Beta (0.8), Negative Factor Loadings (Inefficient)
  const worstBeta = 0.8;
  const worstSMB = -0.5 * SMB_PREMIUM;
  const worstRMW = -0.5 * RMW_PREMIUM;
  const worstCMA = -0.5 * CMA_PREMIUM;
  const worstHML = -0.5 * HML_PREMIUM; 
  const worstAnnual = RISK_FREE_RATE + (worstBeta * marketPremium) + worstSMB + worstRMW + worstCMA + worstHML;
  const worstDrift = toWeeklyRate(worstAnnual - 0.02); // Penalty

  // Moderate: User Config weights (Partial Efficiency)
  const modBeta = config.betaWeight * marketPremium;
  const modSMB = config.smbWeight * SMB_PREMIUM;
  const modRmw = config.rmwWeight * RMW_PREMIUM * 0.6; 
  const modCma = config.cmaWeight * CMA_PREMIUM * 0.6;
  const modHml = config.hmlWeight * HML_PREMIUM * 0.6; 
  const modAnnual = RISK_FREE_RATE + modBeta + modSMB + modRmw + modCma + modHml;
  const modDrift = toWeeklyRate(modAnnual);

  // Best: High Efficiency, Full Premiums
  const bestBeta = config.betaWeight * marketPremium;
  const bestSMB = config.smbWeight * SMB_PREMIUM; 
  const bestRmw = config.rmwWeight * RMW_PREMIUM * 1.2;
  const bestCma = config.cmaWeight * CMA_PREMIUM * 1.2;
  const bestHml = config.hmlWeight * HML_PREMIUM * 1.2;
  const bestAnnual = RISK_FREE_RATE + bestBeta + bestSMB + bestRmw + bestCma + bestHml;
  const bestDrift = toWeeklyRate(bestAnnual + 0.01); // Alpha boost

  // Metrics to return for UI visualization (Theoretical Signal without Noise)
  const metrics: SimulationMetrics = {
    worstCAGR: worstAnnual - 0.02,
    moderateCAGR: modAnnual,
    bestCAGR: bestAnnual + 0.01
  };

  for (let i = 1; i <= totalWeeks; i++) {
    const newDate = new Date(startDate);
    newDate.setDate(startDate.getDate() + (i * 7));
    const dateStr = formatDate(newDate); 
    const timestamp = newDate.getTime();

    // --- Apply Selected Model Logic ---

    if (config.modelType === 'LSTM' || config.modelType === 'GRU') {
        // Recurrent Logic
        const r1 = calculateLSTMNextStep(val1, worstDrift, simVol * 0.8, m1);
        val1 = r1.val; m1 = r1.momentum;

        const r2 = calculateLSTMNextStep(val2, modDrift, simVol * 0.8, m2);
        val2 = r2.val; m2 = r2.momentum;

        const r3 = calculateLSTMNextStep(val3, bestDrift, simVol * 0.8, m3);
        val3 = r3.val; m3 = r3.momentum;

    } else if (config.modelType === 'XGBoost') {
        // Boosting Logic
        val1 = calculateBoostingNextStep(val1, worstDrift, simVol * 1.2);
        val2 = calculateBoostingNextStep(val2, modDrift, simVol * 1.2);
        val3 = calculateBoostingNextStep(val3, bestDrift, simVol * 1.2);

    } else {
        // Fama-French Standard
        val1 = calculateStandardNextStep(val1, worstDrift, simVol);
        val2 = calculateStandardNextStep(val2, modDrift, simVol);
        val3 = calculateStandardNextStep(val3, bestDrift, simVol);
    }

    alt1.push({
      date: dateStr, timestamp, value: val1, ratio: val1 / startValue,
      type: 'Prediction', marketName: 'Worst Case', scenario: 'alt1_worst'
    });

    alt2.push({
      date: dateStr, timestamp, value: val2, ratio: val2 / startValue,
      type: 'Prediction', marketName: 'Moderate Case', scenario: 'alt2_moderate'
    });

    alt3.push({
      date: dateStr, timestamp, value: val3, ratio: val3 / startValue,
      type: 'Prediction', marketName: 'Best Case', scenario: 'alt3_best'
    });
  }

  return { alt1, alt2, alt3, metrics };
};

import React, { useState, useEffect, useCallback, ReactNode } from 'react';
import { generateAllMarketData, runSimulation } from './services/dataService';
import SimulationChart from './components/SimulationChart';
import ControlPanel from './components/ControlPanel';
import { DataPoint, SimulationConfig, SimulationMetrics } from './types';

// Error Boundary to catch render issues
interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
}

class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(_: Error): ErrorBoundaryState {
    return { hasError: true };
  }

  render() {
    if (this.state.hasError) {
      return <div className="p-10 text-center text-red-600">Something went wrong. Please refresh the page.</div>;
    }
    return this.props.children;
  }
}

const AppContent = () => {
  const [loading, setLoading] = useState(true);
  const [datasets, setDatasets] = useState<any>(null);

  // Config State with Fama-French & AI defaults
  const [config, setConfig] = useState<SimulationConfig>({
    betaWeight: 1.0, // Market Sensitivity
    smbWeight: 0.2,  // Size Premium (Slight positive bias)
    rmwWeight: 1.0,  // Profitability (Default 1.0 beta)
    cmaWeight: 1.0,  // Investment Efficiency
    hmlWeight: 1.0,  // Value Re-rating
    volatility: 5.0,
    durationMonths: 60, // Default to 60 months (5 years)
    referenceMarket: 'Japan',
    targetIndex: 'KOSPI',
    historyCutoffYear: 2025, // Default to 2025
    modelType: 'FamaFrench' // Default Model
  });

  // Simulation Results Container
  const [simResults, setSimResults] = useState<{
    targetIndex: string;
    alt1: DataPoint[];
    alt2: DataPoint[];
    alt3: DataPoint[];
    metrics?: SimulationMetrics;
  }>({ targetIndex: 'KOSPI', alt1: [], alt2: [], alt3: [] });

  // 1. Initial Data Load
  useEffect(() => {
    const data = generateAllMarketData();
    setDatasets(data);
    setLoading(false);
  }, []);

  // 2. Run Simulation Logic
  const runSim = useCallback((currentDatasets: any, currentConfig: SimulationConfig) => {
    if (!currentDatasets) return;

    const fullHistory: DataPoint[] = currentConfig.targetIndex === 'KOSPI' ? currentDatasets.kospiData : currentDatasets.kosdaqData;

    const effectiveHistory = fullHistory.filter((pt: DataPoint) => {
        const year = parseInt(pt.date.split('-')[0]);
        // If config is 2025, allow all data up to end of 2025 data points
        return year <= currentConfig.historyCutoffYear;
    });

    const results = runSimulation(effectiveHistory, currentConfig);

    setSimResults({
      targetIndex: currentConfig.targetIndex,
      alt1: results.alt1,
      alt2: results.alt2,
      alt3: results.alt3,
      metrics: results.metrics
    });
  }, []);

  const handleManualRun = () => {
    runSim(datasets, config);
  };

  useEffect(() => {
    if (datasets) {
      runSim(datasets, config);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [datasets, config.targetIndex, config.referenceMarket, config.historyCutoffYear, config.modelType, config.betaWeight, config.smbWeight, config.hmlWeight, config.rmwWeight, config.cmaWeight]); 

  if (loading || !datasets) {
    return <div className="h-screen flex items-center justify-center text-slate-500 font-medium">Loading Market Data...</div>;
  }

  const fullHistory = config.targetIndex === 'KOSPI' ? datasets.kospiData : datasets.kosdaqData;
  const currentHistory = fullHistory.filter((pt: DataPoint) => {
      const year = parseInt(pt.date.split('-')[0]);
      return year <= config.historyCutoffYear;
  });

  const currentReference = 
    config.referenceMarket === 'Japan' ? datasets.japanData : 
    config.referenceMarket === 'SP500' ? datasets.sp500Data : 
    config.referenceMarket === 'NASDAQ' ? datasets.nasdaqData : datasets.dowData;

  const isDataSynced = simResults.targetIndex === config.targetIndex;
  const safeAlt1 = isDataSynced ? simResults.alt1 : [];
  const safeAlt2 = isDataSynced ? simResults.alt2 : [];
  const safeAlt3 = isDataSynced ? simResults.alt3 : [];
  const safeMetrics = isDataSynced && simResults.metrics ? simResults.metrics : { worstCAGR: 0, moderateCAGR: 0, bestCAGR: 0 };

  const getLatest = (arr: DataPoint[]) => arr.length > 0 ? arr[arr.length - 1].value : 0;

  const baselineValue = getLatest(currentHistory);
  const getChange = (curr: number) => {
    if (!baselineValue) return 0;
    return ((curr - baselineValue) / baselineValue) * 100;
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 font-sans text-slate-900">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-20">
        <div className="max-w-7xl mx-auto px-4 h-14 flex items-center justify-between">
          <div className="flex items-center gap-2">
             <div className="w-6 h-6 bg-indigo-600 rounded flex items-center justify-center text-white font-bold text-xs">V</div>
             <h1 className="font-bold text-base tracking-tight text-slate-800">Korea Value-Up Simulator</h1>
          </div>
          <div className="text-xs text-slate-400 font-medium">v3.2 (Stochastic Forecast)</div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-6">

        {/* 1. Control Panel (TOP) */}
        <ControlPanel 
          config={config} 
          setConfig={setConfig} 
          onRunSimulation={handleManualRun} 
        />

        {/* 2. Scenario Summary Cards (MIDDLE) */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">

          {/* Worst Case */}
          <div className="bg-white p-5 rounded-lg border border-slate-200 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full bg-slate-300"></div>
            <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-1">Worst Case</h3>
            <div className="flex items-baseline gap-2">
              <span className="text-2xl font-bold text-slate-800">
                {safeAlt1.length > 0 ? Math.round(getLatest(safeAlt1)).toLocaleString() : '-'}
              </span>
              {safeAlt1.length > 0 && (
                <span className={`text-xs font-bold ${getChange(getLatest(safeAlt1)) >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                  {getChange(getLatest(safeAlt1)).toFixed(1)}%
                </span>
              )}
            </div>
             <div className="mt-2 text-[10px] text-slate-400 bg-slate-50 p-1.5 rounded inline-block">
                Theoretical CAGR: <span className="font-semibold text-slate-600">{(safeMetrics.worstCAGR * 100).toFixed(1)}%</span>
            </div>
          </div>

          {/* Moderate Case */}
          <div className="bg-white p-5 rounded-lg border border-blue-200 shadow-sm ring-1 ring-blue-50 relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full bg-blue-500"></div>
            <h3 className="text-[10px] font-bold text-blue-600 uppercase tracking-wider mb-1">Moderate Case (Your Settings)</h3>
             <div className="flex items-baseline gap-2">
              <span className="text-2xl font-bold text-slate-900">
                {safeAlt2.length > 0 ? Math.round(getLatest(safeAlt2)).toLocaleString() : '-'}
              </span>
              {safeAlt2.length > 0 && (
                <span className={`text-xs font-bold ${getChange(getLatest(safeAlt2)) >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                  +{getChange(getLatest(safeAlt2)).toFixed(1)}%
                </span>
              )}
            </div>
            {/* Theoretical Signal Visualization */}
            <div className="mt-2 text-[10px] text-blue-800 bg-blue-50 p-1.5 rounded flex items-center gap-2">
                 <span>Factor Implied Growth:</span>
                 <span className="font-bold">{(safeMetrics.moderateCAGR * 100).toFixed(2)}% / yr</span>
            </div>
            <p className="text-[9px] text-slate-400 mt-1 leading-tight">
               Adjust sliders to change the 'Implied Growth'. Result varies due to market noise.
            </p>
          </div>

          {/* Best Case */}
          <div className="bg-white p-5 rounded-lg border border-slate-200 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full bg-green-500"></div>
            <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-1">Best Case</h3>
             <div className="flex items-baseline gap-2">
              <span className="text-2xl font-bold text-slate-800">
                {safeAlt3.length > 0 ? Math.round(getLatest(safeAlt3)).toLocaleString() : '-'}
              </span>
              {safeAlt3.length > 0 && (
                <span className={`text-xs font-bold ${getChange(getLatest(safeAlt3)) >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                  +{getChange(getLatest(safeAlt3)).toFixed(1)}%
                </span>
              )}
            </div>
             <div className="mt-2 text-[10px] text-slate-400 bg-slate-50 p-1.5 rounded inline-block">
                Theoretical CAGR: <span className="font-semibold text-green-600">{(safeMetrics.bestCAGR * 100).toFixed(1)}%</span>
            </div>
          </div>

        </div>

        {/* 3. Chart (BOTTOM) */}
        <SimulationChart 
          historyData={currentHistory}
          referenceData={currentReference}
          referenceMarket={config.referenceMarket}
          targetIndex={config.targetIndex}
          alt1Data={safeAlt1}
          alt2Data={safeAlt2}
          alt3Data={safeAlt3}
        />

        {/* Footer Note */}
        <div className="mt-8 text-center text-[10px] text-slate-400">
          <p>
            Data Source: <strong>Historical Data (Approximated Weekly)</strong>.
            <br />
            Methodology: Fama-French 5-Factor Model (2015) + AI Forecast ({config.modelType}). 
            <br/>
            Model = RiskFree + Beta*(Rm-Rf) + s*SMB + h*HML + r*RMW + c*CMA
          </p>
        </div>

      </main>
    </div>
  );
};

