export type ScenarioType = 'history' | 'alt1_worst' | 'alt2_moderate' | 'alt3_best';
export type ReferenceMarket = 'Japan' | 'SP500' | 'NASDAQ' | 'DowJones';
export type TargetIndex = 'KOSPI' | 'KOSDAQ';
export type ModelType = 'FamaFrench' | 'LSTM' | 'GRU' | 'XGBoost';

export interface DataPoint {
  date: string; // YYYY-MM
  timestamp: number;
  value: number; // The actual index value
  ratio?: number; // Percentage growth from simulation start
  type: 'Reference' | 'Target' | 'Prediction';
  marketName?: string; 
  scenario: ScenarioType;
}

export interface SimulationConfig {
  // Fama-French 5-Factor Inputs
  betaWeight: number;   // Market Risk (Mkt-RF): Sensitivity to market movement (0.5 - 2.0)
  smbWeight: number;    // Size (Small Minus Big): Small cap premium ( -1.0 to 1.0)
  rmwWeight: number;    // Profitability (Robust Minus Weak): Quality of Earnings (0.0 - 2.0)
  cmaWeight: number;    // Investment (Conservative Minus Aggressive): Capital Efficiency/Returns (0.0 - 2.0)
  hmlWeight: number;    // Value (High Minus Low): Re-rating intensity for low P/B stocks (0.0 - 2.0)

  // New 6th Factor: Policy
  policyWeight: number; // Policy Drive Strength (0.0 - 1.0)

  volatility: number;   // Random noise level (1 - 10)
  durationMonths: number; // 12 - 120
  referenceMarket: ReferenceMarket;
  targetIndex: TargetIndex;
  historyCutoffYear: number; // Limit historical data to this year

  // AI Model Selection
  modelType: ModelType;
}

export interface SimulationMetrics {
  worstCAGR: number;
  moderateCAGR: number;
  bestCAGR: number;
}

