  // 1. Initial Data Load
  useEffect(() => {
    const data = generateAllMarketData();
    setDatasets(data);
    setLoading(false);
  }, []);

  // 2. Run Simulation Logic
  const runSim = useCallback((currentDatasets: any, currentConfig: SimulationConfig) => {
    if (!currentDatasets) return;

    const fullHistory: DataPoint[] = currentConfig.targetIndex === 'KOSPI' ? currentDatasets.kospiData : currentDatasets.kosdaqData;

    const effectiveHistory = fullHistory.filter((pt: DataPoint) => {
        const year = parseInt(pt.date.split('-')[0]);
        // If config is 2025, allow all data up to end of 2025 data points
        return year <= currentConfig.historyCutoffYear;
    });

    const results = runSimulation(effectiveHistory, currentConfig);

    setSimResults({
      targetIndex: currentConfig.targetIndex,
      alt1: results.alt1,
      alt2: results.alt2,
      alt3: results.alt3,
      metrics: results.metrics
    });
  }, []);

  const handleManualRun = () => {
    runSim(datasets, config);
  };

  useEffect(() => {
    if (datasets) {
      runSim(datasets, config);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [
      datasets, 
      config.targetIndex, 
      config.referenceMarket, 
      config.historyCutoffYear, 
      config.modelType, 
      config.betaWeight, 
      config.smbWeight, 
      config.hmlWeight, 
      config.rmwWeight, 
      config.cmaWeight,
      config.policyWeight
  ]); 

  if (loading || !datasets) {
    return <div className="h-screen flex items-center justify-center text-slate-500 font-medium">Loading Market Data...</div>;
  }

  const fullHistory = config.targetIndex === 'KOSPI' ? datasets.kospiData : datasets.kosdaqData;
  const currentHistory = fullHistory.filter((pt: DataPoint) => {
      const year = parseInt(pt.date.split('-')[0]);
      return year <= config.historyCutoffYear;
  });

  const currentReference = 
    config.referenceMarket === 'Japan' ? datasets.japanData : 
    config.referenceMarket === 'SP500' ? datasets.sp500Data : 
    config.referenceMarket === 'NASDAQ' ? datasets.nasdaqData : datasets.dowData;

  const isDataSynced = simResults.targetIndex === config.targetIndex;
  const safeAlt1 = isDataSynced ? simResults.alt1 : [];
  const safeAlt2 = isDataSynced ? simResults.alt2 : [];
  const safeAlt3 = isDataSynced ? simResults.alt3 : [];
  const safeMetrics = isDataSynced && simResults.metrics ? simResults.metrics : { worstCAGR: 0, moderateCAGR: 0, bestCAGR: 0 };

  const getLatest = (arr: DataPoint[]) => arr.length > 0 ? arr[arr.length - 1].value : 0;

  const baselineValue = getLatest(currentHistory);
  const getChange = (curr: number) => {
    if (!baselineValue) return 0;
    return ((curr - baselineValue) / baselineValue) * 100;
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 font-sans text-slate-900">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-20">
        <div className="max-w-7xl mx-auto px-4 h-14 flex items-center justify-between">
          <div className="flex items-center gap-2">
             <div className="w-6 h-6 bg-indigo-600 rounded flex items-center justify-center text-white font-bold text-xs">V</div>
             <h1 className="font-bold text-base tracking-tight text-slate-800">Korea Value-Up Simulator</h1>
          </div>
          <div className="text-xs text-slate-400 font-medium">v3.3 (Policy Factor Added)</div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-6">

        {/* 1. Control Panel (TOP) */}
        <ControlPanel 
          config={config} 
          setConfig={setConfig} 
          onRunSimulation={handleManualRun} 
        />

        {/* 2. Scenario Summary Cards (MIDDLE) */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">

          {/* Worst Case */}
          <div className="bg-white p-5 rounded-lg border border-slate-200 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full bg-slate-300"></div>
            <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-1">Worst Case</h3>
            <div className="flex items-baseline gap-2">
              <span className="text-2xl font-bold text-slate-800">
                {safeAlt1.length > 0 ? Math.round(getLatest(safeAlt1)).toLocaleString() : '-'}
              </span>
              {safeAlt1.length > 0 && (
                <span className={`text-xs font-bold ${getChange(getLatest(safeAlt1)) >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                  {getChange(getLatest(safeAlt1)).toFixed(1)}%
                </span>
              )}
            </div>
             <div className="mt-2 text-[10px] text-slate-400 bg-slate-50 p-1.5 rounded inline-block">
                Theoretical CAGR: <span className="font-semibold text-slate-600">{(safeMetrics.worstCAGR * 100).toFixed(1)}%</span>
            </div>
          </div>

          {/* Moderate Case */}
          <div className="bg-white p-5 rounded-lg border border-blue-200 shadow-sm ring-1 ring-blue-50 relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full bg-blue-500"></div>
            <h3 className="text-[10px] font-bold text-blue-600 uppercase tracking-wider mb-1">Moderate Case (Your Settings)</h3>
             <div className="flex items-baseline gap-2">
              <span className="text-2xl font-bold text-slate-900">
                {safeAlt2.length > 0 ? Math.round(getLatest(safeAlt2)).toLocaleString() : '-'}
              </span>
              {safeAlt2.length > 0 && (
                <span className={`text-xs font-bold ${getChange(getLatest(safeAlt2)) >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                  +{getChange(getLatest(safeAlt2)).toFixed(1)}%
                </span>
              )}
            </div>
            {/* Theoretical Signal Visualization */}
            <div className="mt-2 text-[10px] text-blue-800 bg-blue-50 p-1.5 rounded flex items-center gap-2">
                 <span>Factor Implied Growth:</span>
                 <span className="font-bold">{(safeMetrics.moderateCAGR * 100).toFixed(2)}% / yr</span>
            </div>
            <p className="text-[9px] text-slate-400 mt-1 leading-tight">
               Adjust sliders to change the 'Implied Growth'. Result varies due to market noise.
            </p>
          </div>

          {/* Best Case */}
          <div className="bg-white p-5 rounded-lg border border-slate-200 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full bg-green-500"></div>
            <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-1">Best Case</h3>
             <div className="flex items-baseline gap-2">
              <span className="text-2xl font-bold text-slate-800">
                {safeAlt3.length > 0 ? Math.round(getLatest(safeAlt3)).toLocaleString() : '-'}
              </span>
              {safeAlt3.length > 0 && (
                <span className={`text-xs font-bold ${getChange(getLatest(safeAlt3)) >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                  +{getChange(getLatest(safeAlt3)).toFixed(1)}%
                </span>
              )}
            </div>
             <div className="mt-2 text-[10px] text-slate-400 bg-slate-50 p-1.5 rounded inline-block">
                Theoretical CAGR: <span className="font-semibold text-green-600">{(safeMetrics.bestCAGR * 100).toFixed(1)}%</span>
            </div>
          </div>

        </div>

        {/* 3. Chart (BOTTOM) */}
        <SimulationChart 
          historyData={currentHistory}
          referenceData={currentReference}
          referenceMarket={config.referenceMarket}
          targetIndex={config.targetIndex}
          alt1Data={safeAlt1}
          alt2Data={safeAlt2}
          alt3Data={safeAlt3}
        />

        {/* Footer Note */}
        <div className="mt-8 text-center text-[10px] text-slate-400">
          <p>
            Data Source: <strong>Historical Data (Approximated Weekly)</strong>.
            <br />
            Methodology: Fama-French 5-Factor + Policy Alpha + AI Forecast ({config.modelType}). 
            <br/>
            Model = RiskFree + Beta*(Rm-Rf) + s*SMB + h*HML + r*RMW + c*CMA + p*Policy
          </p>
        </div>

      </main>
    </div>
  );
};

export default function App() {
  return (
    <ErrorBoundary>
      <AppContent />
    </ErrorBoundary>
  );
}

